// Normalize an Apollo person + org into our lead shape, then classify.
// classifyLead() below is the canonical copy from scripts/icp_filter.js — KEEP IN SYNC.

const DROPSHIP = [/\bdropship(ping)?\b/i, /\baliexpress\b/i, /\bprint on demand\b/i, /\bpod\b/i];
const BRICK = [/\blocal\b/i, /\brestaurant\b/i, /\bsalon\b/i, /\bdentist\b/i, /\bchiropractor\b/i, /\bretail store\b/i];
const ECOM = ["shopify","woocommerce","bigcommerce","magento","ecommerce","e-commerce","dtc"];
const INFO = ["coach","course","consultant","mastermind","program","mentor","info product","online business","agency"];
const MIN_MONTHLY_REVENUE = 100000;
const MAX_EMPLOYEES = 500;
const anyMatch = (ps, t) => ps.some(re => re.test(t || ""));
const anyIncludes = (ns, arr) => { const hay = (arr||[]).join(" ").toLowerCase(); return ns.some(n => hay.includes(n)); };
function classifyLead(raw){
  const name = raw.company_name||""; const desc = raw.description||""; const nameDesc = `${name} ${desc}`;
  const domain = (raw.domain||"").toLowerCase(); const keywords = raw.keywords||[];
  // Apollo returns 0 for undisclosed revenue — treat 0 as UNKNOWN, not a real zero.
  const _rev = raw.annual_revenue_usd;
  const monthlyRevenue = (_rev != null && _rev > 0) ? _rev/12 : null;
  if (anyMatch(DROPSHIP,nameDesc)) return arch("dropshipper");
  if (anyMatch(BRICK,desc)) return arch("brick_and_mortar");
  if (raw.employee_count!=null && raw.employee_count>MAX_EMPLOYEES) return arch("too_enterprise");
  if (/\.(local|city)$/.test(domain)) return arch("geo_local_domain");
  const looksEcom = anyIncludes(ECOM,keywords)||anyIncludes(ECOM,[nameDesc]);
  const looksInfo = anyIncludes(INFO,keywords)||anyIncludes(INFO,[nameDesc]);
  if (monthlyRevenue!=null && monthlyRevenue<MIN_MONTHLY_REVENUE) return arch("below_revenue_threshold");
  // Apollo rarely has real revenue for small info businesses; unknown revenue is NOT a
  // disqualifier. Let the live audit be the real qualifier downstream.
  if (looksEcom) return rt("secondary_ecom","high");
  if (looksInfo) return rt("primary_info","high");
  return rt("primary_info","low");
}
const arch = r => ({icp_tier:"disqualified",is_archived:true,archive_reason:r,routing_confidence:"n/a"});
const rt = (t,c) => ({icp_tier:t,is_archived:false,archive_reason:null,routing_confidence:c});

function hostname(url){ try { return new URL(url.startsWith("http")?url:`https://${url}`).hostname.replace(/^www\./,""); } catch { return null; } }

const out = [];
for (const item of $input.all()) {
  const p = item.json;
  const org = p.organization || {};
  // domain: prefer org website, else derive from the founder email (reveal responses
  // often have thin org data), else skip.
  const emailDomain = (p.email && p.email.includes("@") && !/email_not_unlocked/i.test(p.email))
    ? p.email.split("@")[1].toLowerCase() : null;
  const domain = hostname(org.website_url || org.primary_domain || "") || emailDomain;
  if (!domain) continue;
  const raw = {
    domain,
    company_name: org.name || (p.employment_history && p.employment_history[0] && p.employment_history[0].organization_name) || null,
    description: org.short_description || org.seo_description || "",
    keywords: [].concat(org.keywords || [], org.industry ? [org.industry] : []).map(s => String(s).toLowerCase()),
    employee_count: org.estimated_num_employees ?? null,
    annual_revenue_usd: org.annual_revenue ?? org.organization_revenue ?? null
  };
  const c = classifyLead(raw);
  out.push({ json: {
    domain: raw.domain,
    company_name: raw.company_name,
    founder_name: p.name || null,
    founder_email: p.email && !/email_not_unlocked/i.test(p.email) ? p.email : null,
    founder_linkedin_url: p.linkedin_url || null,
    founder_ig_handle: null,
    source: "apollo",
    source_metadata: {
      apollo_person_id: p.id || null,
      title: p.title || null,
      employee_count: raw.employee_count,
      annual_revenue_usd: raw.annual_revenue_usd,
      keywords: raw.keywords,
      routing_confidence: c.routing_confidence
    },
    icp_tier: c.icp_tier,
    is_archived: c.is_archived,
    archive_reason: c.archive_reason
  }});
}
return out;

// Summarize the run for the Discord digest.
const rows = $input.first().json.data || [];
const inserted = rows.filter(r => r && r.id).length;
const byTier = {};
for (const r of $('Normalize & Classify').all()) {
  const t = r.json.is_archived ? `archived:${r.json.archive_reason}` : r.json.icp_tier;
  byTier[t] = (byTier[t]||0)+1;
}
const lines = Object.entries(byTier).map(([k,v]) => `• ${k}: ${v}`).join('\n');
return [{ json: { content: `**Apollo sourcing run** — ${new Date().toISOString().slice(0,10)}\nNew rows inserted: ${inserted}\n${lines || '(no leads returned)'}` } }];

// people/match returns { person: {...} }. Emit that person (with revealed email)
const p = $json.person || $json;
if (!p || (!p.email && !p.id)) { return []; }  // skip if reveal failed
return [{ json: p }];
